python
class Engine:
    def __init__(self, fuel_line_intact=True):
        self.fuel_line_intact = fuel_line_intact
        self.power_status = 'running'

    def check_power(self):
        if not self.fuel_line_intact:
            self.power_status = 'failed'
        return self.power_status

class Aircraft:
    def __init__(self):
        self.engine1 = Engine(fuel_line_intact=False)
        self.engine2 = Engine(fuel_line_intact=False)

    def check_engines(self):
        return [engine.check_power() for engine in [self.engine1, self.engine2]]

# Simulate the fuel line failure in Dana Air Flight 0992
aircraft = Aircraft()
engine_status = aircraft.check_engines()
print(f'Engine Status: {engine_status}')
# Output: Engine Status: ['failed', 'failed']

This simplified code demonstrates how severed fuel lines in both engines lead to a loss of power, analogous to the incident in Dana Air Flight 0992.
